// 작업장별 ZONE 정보 그리드 행추가
//-------------------------------------------------------------------------
scwin.f_AddRowMain = function () {
    scwin.f_AddRow('main');
};

//-------------------------------------------------------------------------
// 작업장별 ZONE 정보 그리드 행삭제
//-------------------------------------------------------------------------
